visualizerParams.buggyCode:
interface Drawable {
    void draw();
}

class Circle implements Drawable {
    void draw() { // BUG: Missing 'public' modifier
        System.out.println("Drawing...");
    }
}

solution.code:
interface Drawable {
    void draw();
}

class Circle implements Drawable {
    @Override
    public void draw() {
        System.out.println("Drawing...");
    }
}
